body {
  font-family: "BrandFont Display", "Helvetica Neue", Arial, sans-serif;
  font-size: 1.125rem; /* Base 18px */
  font-size-adjust: 0.52; /* Set to the aspect value (x-height to font-size ratio) of "BrandFont Display" */
}

h1 {
  font-family: "BrandFont Heading", Georgia, serif;
  font-size: 2.5rem; /* Base 40px */
  font-size-adjust: 0.48; /* Set to the aspect value of "BrandFont Heading" */
}
